/*
 * mavlink-browser.js  —  killinchu JACK-IN console (Dev 1)
 * --------------------------------------------------------------------------
 * VENDORING NOTE (read this):
 *   We evaluated the npm package `mavlink-browser@1.5.0`
 *   (https://github.com/neelsani/mavlink-browser, MIT). Its shipped browser
 *   build (dist/mavlink.js, ~984 KB) is auto-generated by mavgen and depends
 *   on Node CommonJS modules: require("./jspack"), require("underscore"),
 *   require("events"), require("util"), and the Node `Buffer` global. Running
 *   it in a plain browser with ZERO runtime CDN would require bundling four
 *   dependencies plus Buffer/util polyfills — heavy and brittle for a static,
 *   self-hosted demo surface.
 *
 *   DECISION: we hand-vendored a CORRECT, fully self-contained MAVLink v1/v2
 *   frame parser for exactly the messages the JACK-IN pipeline needs:
 *     HEARTBEAT(0), SYS_STATUS(1), GPS_RAW_INT(24), ATTITUDE(30),
 *     GLOBAL_POSITION_INT(33).
 *   The CRC-16/MCRF4XX (x25) routine and the CRC_EXTRA seeds + wire field
 *   layouts below were taken verbatim from that same upstream library's
 *   generated tables, so framing/CRC behaviour is byte-identical to the real
 *   thing for these message IDs. 0 dependencies, 0 CDN, ~10 KB.
 *
 * Exposes: window.MAVLinkBrowser = { Parser, MSG, x25crc, CRC_EXTRA }
 * Usage:
 *   const p = new MAVLinkBrowser.Parser();
 *   p.onMessage = (msg) => { ... msg.name, msg.fields ... };
 *   p.push(uint8ArrayChunk);   // call repeatedly with serial/BLE byte chunks
 * --------------------------------------------------------------------------
 */
(function (global) {
  'use strict';

  // ---- MAVLink framing constants ----------------------------------------
  var STX_V1 = 0xFE;     // MAVLink 1 start byte
  var STX_V2 = 0xFD;     // MAVLink 2 start byte

  // CRC_EXTRA seeds (from upstream mavgen tables) for our target messages.
  var CRC_EXTRA = {
    0:  50,   // HEARTBEAT
    1:  124,  // SYS_STATUS
    24: 24,   // GPS_RAW_INT
    30: 39,   // ATTITUDE
    33: 104   // GLOBAL_POSITION_INT
  };

  var MSG = {
    HEARTBEAT: 0,
    SYS_STATUS: 1,
    GPS_RAW_INT: 24,
    ATTITUDE: 30,
    GLOBAL_POSITION_INT: 33
  };
  var MSG_NAME = {
    0: 'HEARTBEAT', 1: 'SYS_STATUS', 24: 'GPS_RAW_INT',
    30: 'ATTITUDE', 33: 'GLOBAL_POSITION_INT'
  };

  // Expected payload length (un-truncated, wire order) per message id.
  // MAVLink v2 may truncate trailing zero bytes; we right-pad to this length
  // before parsing so fixed-offset reads are always valid.
  var MSG_LEN = {
    0:  9,    // HEARTBEAT  <IBBBBB  = 4+1+1+1+1+1
    1:  31,   // SYS_STATUS <IIIHHhHHHHHHbIII
    24: 52,   // GPS_RAW_INT (with ext fields) — base 30, padded ok
    30: 28,   // ATTITUDE   <Iffffff = 4 + 6*4
    33: 28    // GLOBAL_POSITION_INT <IiiiihhhH = 4 + 4*4 + 3*2 + 2
  };

  // ---- CRC-16/MCRF4XX (a.k.a. x25) — verbatim from upstream --------------
  function x25crc(bytes, start, end, crcIn) {
    var crc = (crcIn === undefined) ? 0xffff : crcIn;
    for (var i = start; i < end; i++) {
      var tmp = (bytes[i] ^ (crc & 0xff)) & 0xff;
      tmp = (tmp ^ (tmp << 4)) & 0xff;
      crc = ((crc >> 8) ^ (tmp << 8) ^ (tmp << 3) ^ (tmp >> 4)) & 0xffff;
    }
    return crc & 0xffff;
  }

  // ---- little-endian readers --------------------------------------------
  function rd(dv, off) {
    return {
      u8:  function () { return dv.getUint8(off); },
      i8:  function () { return dv.getInt8(off); },
      u16: function () { return dv.getUint16(off, true); },
      i16: function () { return dv.getInt16(off, true); },
      u32: function () { return dv.getUint32(off, true); },
      i32: function () { return dv.getInt32(off, true); },
      f32: function () { return dv.getFloat32(off, true); }
    };
  }

  // Decode the payload bytes (already right-padded) for a known message id.
  // Field byte offsets follow the WIRE order produced by mavgen's order_map.
  function decodePayload(id, p) {
    var dv = new DataView(p.buffer, p.byteOffset, p.byteLength);
    var f = {};
    switch (id) {
      case 0: // HEARTBEAT  wire: custom_mode(I) type(B) autopilot(B) base_mode(B) system_status(B) mavlink_version(B)
        f.custom_mode      = dv.getUint32(0, true);
        f.type             = dv.getUint8(4);
        f.autopilot        = dv.getUint8(5);
        f.base_mode        = dv.getUint8(6);
        f.system_status    = dv.getUint8(7);
        f.mavlink_version  = dv.getUint8(8);
        break;
      case 1: // SYS_STATUS wire: present(I) enabled(I) health(I) load(H) voltage_battery(H) current_battery(h) ... battery_remaining(b)@offset 30
        f.onboard_control_sensors_present = dv.getUint32(0, true);
        f.load             = dv.getUint16(12, true);
        f.voltage_battery  = dv.getUint16(14, true);   // mV
        f.current_battery  = dv.getInt16(16, true);    // cA
        f.battery_remaining = dv.getInt8(30);          // percent (-1 = unknown)
        break;
      case 24: // GPS_RAW_INT wire: time(Q@0) lat(i@8) lon(i@12) alt(i@16) eph(H@20) epv(H@22) vel(H@24) cog(H@26) fix_type(B@28) sats(B@29)
        f.lat              = dv.getInt32(8, true);     // 1e7 deg
        f.lon              = dv.getInt32(12, true);    // 1e7 deg
        f.alt              = dv.getInt32(16, true);    // mm MSL
        f.eph              = dv.getUint16(20, true);
        f.vel              = dv.getUint16(24, true);   // cm/s
        f.cog              = dv.getUint16(26, true);   // cdeg
        f.fix_type         = dv.getUint8(28);
        f.satellites_visible = dv.getUint8(29);
        break;
      case 30: // ATTITUDE wire: time(I@0) roll(f@4) pitch(f@8) yaw(f@12) rollspeed(f@16) pitchspeed(f@20) yawspeed(f@24)
        f.time_boot_ms     = dv.getUint32(0, true);
        f.roll             = dv.getFloat32(4, true);   // rad
        f.pitch            = dv.getFloat32(8, true);   // rad
        f.yaw              = dv.getFloat32(12, true);  // rad
        break;
      case 33: // GLOBAL_POSITION_INT wire: time(I@0) lat(i@4) lon(i@8) alt(i@12) rel_alt(i@16) vx(h@20) vy(h@22) vz(h@24) hdg(H@26)
        f.time_boot_ms     = dv.getUint32(0, true);
        f.lat              = dv.getInt32(4, true);     // 1e7 deg
        f.lon              = dv.getInt32(8, true);     // 1e7 deg
        f.alt              = dv.getInt32(12, true);    // mm MSL
        f.relative_alt     = dv.getInt32(16, true);    // mm
        f.vx               = dv.getInt16(20, true);    // cm/s
        f.vy               = dv.getInt16(22, true);    // cm/s
        f.vz               = dv.getInt16(24, true);    // cm/s
        f.hdg              = dv.getUint16(26, true);    // cdeg (0..35999), 65535=unknown
        break;
      default:
        return null;
    }
    return f;
  }

  // ---- Streaming parser --------------------------------------------------
  // Handles both MAVLink v1 (0xFE) and v2 (0xFD) frames, including v2 payload
  // truncation and the v2 signature trailer (13 bytes, skipped). Resyncs on
  // bad CRC by advancing one byte past the false start marker.
  function Parser() {
    this.buf = new Uint8Array(0);
    this.onMessage = null;     // (msg) => void
    this.stats = { frames: 0, crcErrors: 0, bytes: 0, lastSeq: -1, dropped: 0 };
  }

  Parser.prototype._append = function (chunk) {
    if (!(chunk instanceof Uint8Array)) chunk = new Uint8Array(chunk);
    var merged = new Uint8Array(this.buf.length + chunk.length);
    merged.set(this.buf, 0);
    merged.set(chunk, this.buf.length);
    this.buf = merged;
    this.stats.bytes += chunk.length;
  };

  Parser.prototype.push = function (chunk) {
    this._append(chunk);
    var b = this.buf;
    var i = 0;
    var n = b.length;

    while (i < n) {
      var stx = b[i];
      if (stx !== STX_V1 && stx !== STX_V2) { i++; continue; }

      var isV2 = (stx === STX_V2);
      var hdrLen = isV2 ? 10 : 6;
      if (i + hdrLen > n) break; // need more header bytes

      var payLen = b[i + 1];
      var seq, sysid, compid, msgid, incompatFlags = 0;
      var payOff;

      if (isV2) {
        incompatFlags = b[i + 2];
        // compatFlags = b[i+3]
        seq    = b[i + 4];
        sysid  = b[i + 5];
        compid = b[i + 6];
        msgid  = b[i + 7] | (b[i + 8] << 8) | (b[i + 9] << 16); // 24-bit LE
        payOff = i + 10;
      } else {
        seq    = b[i + 2];
        sysid  = b[i + 3];
        compid = b[i + 4];
        msgid  = b[i + 5];
        payOff = i + 6;
      }

      var crcOff = payOff + payLen;            // 2-byte CRC after payload
      var sigLen = (isV2 && (incompatFlags & 0x01)) ? 13 : 0; // MAVLINK_IFLAG_SIGNED
      var frameEnd = crcOff + 2 + sigLen;
      if (frameEnd > n) break;                 // need more bytes for full frame

      // CRC is computed over [len .. end-of-payload] + crc_extra seed.
      var crcExtra = CRC_EXTRA[msgid];
      // CRC range: from byte after STX through end of payload.
      var crc = x25crc(b, i + 1, crcOff, 0xffff);
      if (crcExtra !== undefined) {
        crc = x25crc([crcExtra], 0, 1, crc);
      }
      var rxCrc = b[crcOff] | (b[crcOff + 1] << 8);

      if (crcExtra === undefined) {
        // Unknown msg id (not in our table) — can't validate crc_extra.
        // Advance past header to avoid infinite loop; we only surface known msgs.
        i++;
        continue;
      }

      if (crc !== rxCrc) {
        this.stats.crcErrors++;
        i++;            // false marker / corrupt — resync one byte forward
        continue;
      }

      // Valid frame.
      this.stats.frames++;
      if (this.stats.lastSeq >= 0) {
        var exp = (this.stats.lastSeq + 1) & 0xff;
        if (seq !== exp) this.stats.dropped += ((seq - exp) & 0xff);
      }
      this.stats.lastSeq = seq;

      // Right-pad truncated v2 payloads to full length for fixed-offset reads.
      var fullLen = MSG_LEN[msgid] || payLen;
      var payload = new Uint8Array(Math.max(fullLen, payLen));
      payload.set(b.subarray(payOff, payOff + payLen), 0);

      var fields = decodePayload(msgid, payload);
      if (fields && typeof this.onMessage === 'function') {
        this.onMessage({
          version: isV2 ? 2 : 1,
          msgid: msgid,
          name: MSG_NAME[msgid] || ('MSG_' + msgid),
          seq: seq, sysid: sysid, compid: compid,
          fields: fields,
          raw: b.subarray(i, frameEnd).slice()
        });
      }

      i = frameEnd; // consume frame
    }

    // Retain unparsed tail.
    this.buf = (i > 0) ? b.subarray(i).slice() : b;
    return this.stats.frames;
  };

  Parser.prototype.reset = function () {
    this.buf = new Uint8Array(0);
    this.stats = { frames: 0, crcErrors: 0, bytes: 0, lastSeq: -1, dropped: 0 };
  };

  // ---- Minimal v2 ENCODER (used by SITL sample source to produce real frames)
  // Builds a correctly-CRC'd MAVLink v2 frame for a known msg id from a
  // full-length, wire-order payload Uint8Array. Lets the SAMPLE source feed
  // the exact same parser path the real radio would.
  function encodeV2(msgid, payload, seq, sysid, compid) {
    seq = seq & 0xff; sysid = sysid || 1; compid = compid || 1;
    var len = payload.length;
    var frame = new Uint8Array(10 + len + 2);
    frame[0] = STX_V2;
    frame[1] = len;
    frame[2] = 0;   // incompat flags
    frame[3] = 0;   // compat flags
    frame[4] = seq;
    frame[5] = sysid;
    frame[6] = compid;
    frame[7] = msgid & 0xff;
    frame[8] = (msgid >> 8) & 0xff;
    frame[9] = (msgid >> 16) & 0xff;
    frame.set(payload, 10);
    var crc = x25crc(frame, 1, 10 + len, 0xffff);
    var ce = CRC_EXTRA[msgid];
    if (ce !== undefined) crc = x25crc([ce], 0, 1, crc);
    frame[10 + len] = crc & 0xff;
    frame[10 + len + 1] = (crc >> 8) & 0xff;
    return frame;
  }

  global.MAVLinkBrowser = {
    Parser: Parser,
    encodeV2: encodeV2,
    x25crc: x25crc,
    MSG: MSG,
    MSG_NAME: MSG_NAME,
    MSG_LEN: MSG_LEN,
    CRC_EXTRA: CRC_EXTRA,
    STX_V1: STX_V1,
    STX_V2: STX_V2,
    _impl: 'self-contained-minimal'  // vs upstream npm bundle
  };
})(typeof window !== 'undefined' ? window : this);
